select 
from sys_job


    and (
      name like concat('%', #{keyword}, '%')
      or job_group like concat('%', #{keyword}, '%')
      or invoke_target like concat('%', #{keyword}, '%')
    )


    and status = #{status}


order by id asc
limit #{pageSize} offset #{offset}

